module top_module(input clk, input reset, input load, input [3:0] in, output reg [3:0] out);reg [3:0] cnt_reg;

	always @(posedge clk or posedge reset) begin
		if (reset) begin
			cnt_reg <= 4'b0;
		end else begin
			if (load) begin
				cnt_reg <= in;
			end else begin
				cnt_reg <= cnt_reg + 1;
			end
		end
	end

	assign out = cnt_reg;

endmodule
